import { cookies } from "next/headers";
import { redirect } from "next/navigation";

import { getSalesAgentOptions } from "@/utils/sales-team";

const SALES_AGENT_COOKIE = "lead-scorer-sales-agent";

export default async function Home() {
  const salesAgents = await getSalesAgentOptions();

  async function login(formData: FormData) {
    "use server";

    const selectedAgent = String(formData.get("salesAgent") ?? "").trim();
    const isValidAgent = salesAgents.some((agent) => agent.name === selectedAgent);

    if (!isValidAgent) {
      redirect("/");
    }

    const cookieStore = await cookies();

    cookieStore.set(SALES_AGENT_COOKIE, selectedAgent, {
      httpOnly: true,
      maxAge: 60 * 60 * 24 * 30,
      path: "/",
      sameSite: "lax",
      secure: process.env.NODE_ENV === "production",
    });

    redirect("/pipeline");
  }

  return (
    <main className="min-h-screen bg-[radial-gradient(circle_at_top,_#fff8ea,_#f4ede2_40%,_#e7dfd4_100%)] px-6 py-10 text-stone-900 sm:px-10 lg:px-16">
      <div className="mx-auto flex min-h-[calc(100vh-5rem)] max-w-6xl items-center justify-center">
        <section className="grid w-full overflow-hidden rounded-[2rem] border border-stone-900/10 bg-white/85 shadow-[0_30px_90px_rgba(76,61,43,0.16)] backdrop-blur sm:grid-cols-[1.1fr_0.9fr]">
          <div className="flex flex-col justify-between gap-10 bg-stone-950 px-8 py-10 text-stone-100 sm:px-10 sm:py-12">
            <div className="space-y-6">
              <p className="text-xs font-semibold uppercase tracking-[0.3em] text-amber-300/80">
                Challenge 003
              </p>
              <div className="space-y-4">
                <h1 className="max-w-lg text-4xl font-semibold tracking-tight text-balance sm:text-5xl">
                  Start with your deal list, not a blank dashboard.
                </h1>
                <p className="max-w-md text-base leading-7 text-stone-300">
                  Choose your salesperson profile to load the right pipeline and keep
                  the scoring context tied to that selection.
                </p>
              </div>
            </div>

            <div className="grid gap-4 text-sm text-stone-300 sm:grid-cols-2">
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4">
                <p className="font-medium text-stone-50">Transparent prioritization</p>
                <p className="mt-2 leading-6">
                  Every ranked deal can explain the strongest positive and negative
                  drivers behind its score.
                </p>
              </div>
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4">
                <p className="font-medium text-stone-50">Real CRM data</p>
                <p className="mt-2 leading-6">
                  The salesperson list is loaded from the provided sales team CSV, not
                  hardcoded into the UI.
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center bg-[linear-gradient(180deg,_rgba(255,255,255,0.92),_rgba(245,239,231,0.98))] px-8 py-10 sm:px-10 sm:py-12">
            <div className="w-full space-y-8">
              <div className="space-y-3">
                <p className="text-sm font-medium uppercase tracking-[0.24em] text-stone-500">
                  Login
                </p>
                <div className="space-y-2">
                  <h2 className="text-3xl font-semibold tracking-tight text-stone-950">
                    Select your salesperson
                  </h2>
                  <p className="max-w-md text-sm leading-6 text-stone-600">
                    Your choice is stored for the next page so the pipeline can load in
                    the right context immediately after login.
                  </p>
                </div>
              </div>

              <form action={login} className="space-y-5">
                <label className="block space-y-2" htmlFor="salesAgent">
                  <span className="text-sm font-medium text-stone-700">Salesperson</span>
                  <select
                    id="salesAgent"
                    name="salesAgent"
                    className="w-full rounded-2xl border border-stone-300 bg-white px-4 py-3 text-base text-stone-900 outline-none transition focus:border-stone-950"
                    defaultValue=""
                    required
                  >
                    <option disabled value="">
                      Choose a salesperson
                    </option>
                    {salesAgents.map((agent) => (
                      <option key={agent.name} value={agent.name}>
                        {agent.name} - {agent.regionalOffice}
                      </option>
                    ))}
                  </select>
                </label>

                <button
                  className="w-full rounded-2xl bg-stone-950 px-5 py-3 text-sm font-semibold text-stone-50 transition hover:bg-stone-800"
                  type="submit"
                >
                  Log in
                </button>
              </form>
            </div>
          </div>
        </section>
      </div>
    </main>
  );
}
